from django import templatefrom django.db.models.aggregates import Count# from ..models import Comment,Postfrom blog.models import Comment, Postregister = template.Library()@register.simple_tag()def total_comment():    return Comment.objects.filter(active=True).count()@register.simple_tag()def total_post():    return Post.published.count()@register.simple_tag()def most_popular_post(count=3):    return Post.published.annotate(comment_counts=Count('comments')).order_by('-comment_counts')[:count]@register.inclusion_tag("partials/latest_post.html")def latest_post(count=4):    l_post = Post.published.order_by('-publish')[:count]    context = {        'l_post':l_post    }    return context